1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface DamageEntry {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface ClaimStep {
18	  op: "claim";
19	  policy: number;
20	  incident: {
21	    cause: string;
22	    damages: DamageEntry[];
23	  };
24	}
25	
26	type Step = QuoteStep | ClaimStep;
27	
28	interface Scenario {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	}
32	
33	type QuoteResult = { premium: number };
34	type ClaimResult = { payout: number };
35	type StepResult = QuoteResult | ClaimResult;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  amulet: 60,
39	  sword: 100,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const FIRST_INSURANCE_RATE = 0.1;
45	const PROCESSING_FEE = 5;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const LOYALTY_DISCOUNT_RATE = 0.2;
51	const LOYALTY_THRESHOLD_YEARS = 2;
52	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
53	
54	// Component-block pricing: 3 alike components of the same type (e.g. 3 runes
55	// or 3 moonstones) sold together are priced as a 60 G block instead of
56	// 3 ├Ś 25 = 75 G. Adjustment is applied to policy base for each component
57	// type with exactly 3 instances.
58	const COMPONENT_BLOCK_SIZE = 3;
59	const COMPONENT_BLOCK_PRICE = 60;
60	const COMPONENT_TYPES = ["rune", "moonstone"];
61	
62	function sumOver<T>(xs: T[], f: (x: T) => number): number {
63	  return xs.reduce((total, x) => total + f(x), 0);
64	}
65	
66	// MHPCO rounds quote premiums UP (in the office's favor).
67	function roundUpInFavorOfOffice(amount: number): number {
68	  return Math.ceil(amount);
69	}
70	
71	// MHPCO rounds claim payouts DOWN (in the office's favor) ŌĆö symmetric
72	// counterpart of `roundUpInFavorOfOffice` for premiums.
73	function roundDownInFavorOfOffice(amount: number): number {
74	  return Math.floor(amount);
75	}
76	
77	function basePremium(type: string): number {
78	  return BASE_PREMIUM[type] ?? 0;
79	}
80	
81	function itemBasePremium(item: QuoteItem): number {
82	  return basePremium(item.type);
83	}
84	
85	// Per-type adjustment when exactly COMPONENT_BLOCK_SIZE items of `type` are
86	// present in the step: replace raw N ├Ś base with the flat block price.
87	function componentBlockAdjustment(items: QuoteItem[]): number {
88	  return sumOver(COMPONENT_TYPES, (type) => {
89	    const count = items.filter((x) => x.type === type).length;
90	    return count === COMPONENT_BLOCK_SIZE
91	      ? COMPONENT_BLOCK_PRICE - COMPONENT_BLOCK_SIZE * basePremium(type)
92	      : 0;
93	  });
94	}
95	
96	function itemSurcharges(item: QuoteItem): number {
97	  const base = itemBasePremium(item);
98	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
99	  const highEnchantmentSurcharge =
100	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
101	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
102	      : 0;
103	  return curseSurcharge + highEnchantmentSurcharge;
104	}
105	
106	function priceQuoteStep(
107	  step: QuoteStep,
108	  yearsWithMHPCO: number,
109	  isFollowUp: boolean,
110	): QuoteResult {
111	  const policyBase =
112	    sumOver(step.items, itemBasePremium) + componentBlockAdjustment(step.items);
113	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
114	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
115	  const loyaltyDiscount =
116	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
117	      ? policyBase * LOYALTY_DISCOUNT_RATE
118	      : 0;
119	  const followUpDiscount = isFollowUp
120	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
121	    : 0;
122	  const premium = roundUpInFavorOfOffice(
123	    policyBase +
124	      itemSurchargeTotal +
125	      firstInsurance -
126	      loyaltyDiscount -
127	      followUpDiscount +
128	      PROCESSING_FEE,
129	  );
130	  return { premium };
131	}
132	
133	const DEDUCTIBLE_PER_DAMAGE = 100;
134	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
135	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
136	
137	// Payout for a single damage entry: full reimbursement minus a flat
138	// per-damage deductible. Upcoming clauses (high-enchantment 50%,
139	// dragon-material) will compose here, mirroring how `itemSurcharges` is
140	// the home for per-item surcharges in `priceQuoteStep`.
141	function damagePayout(damage: DamageEntry, insuredItem: QuoteItem): number {
142	  const reimbursement =
143	    (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
144	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
145	      : damage.amount;
146	  return reimbursement - DEDUCTIBLE_PER_DAMAGE;
147	}
148	
149	// Resolves which insured item a damage entry refers to, by matching item
150	// type. Returns undefined if the damage's itemType isn't on the policy ŌĆö
151	// upcoming validation tests (claim referencing item not in policy) will
152	// turn this into an explicit error path.
153	function insuredItemFor(
154	  damage: DamageEntry,
155	  policyItems: QuoteItem[],
156	): QuoteItem | undefined {
157	  return policyItems.find((item) => item.type === damage.itemType);
158	}
159	
160	function processClaimStep(step: ClaimStep, policyItems: QuoteItem[]): ClaimResult {
161	  const payout = roundDownInFavorOfOffice(
162	    sumOver(step.incident.damages, (damage) =>
163	      damagePayout(damage, insuredItemFor(damage, policyItems)!),
164	    ),
165	  );
166	  return { payout };
167	}
168	
169	export function runScenario(scenario: Scenario): {
170	  results: StepResult[];
171	} {
172	  const results = scenario.steps.map((step, index) => {
173	    if (step.op === "quote") {
174	      return priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0);
175	    }
176	    const policyStep = scenario.steps[step.policy] as QuoteStep;
177	    return processClaimStep(step, policyStep.items);
178	  });
179	  return { results };
180	}
